const r = await tools.exec_command({"cmd":"for repo in ../cli ../entire.io .; do
  echo "### $repo";
  find "$repo/.entire" -maxdepth 3 -type f -print 2>/dev/null;
  find "$repo/.codex" -maxdepth 3 -type f -print 2>/dev/null;
  find "$repo/.claude" -maxdepth 3 -type f -print 2>/dev/null;
done
printf '\n### CLI runners\n'; for f in ../cli/.entire/* ../cli/cmd/entire/cli/runnerdefaults/runners/*.json; do [ -f "$f" ] && { echo "--- $f"; sed -n '1,220p' "$f"; }; done
printf '\n### entire.io runners\n'; for f in ../entire.io/.entire/*; do [ -f "$f" ] && { echo "--- $f"; sed -n '1,240p' "$f"; }; done
printf '\n### graph settings\n'; find .entire .codex .claude -maxdepth 3 -type f -print -exec sed -n '1,220p' {} \; 2>/dev/null","workdir":"/Users/krk/Desktop/GitStore/entire-graph","yield_time_ms":10000,"max_output_tokens":30000});
text(r.output);

